1	const PROCESSING_FEE = 5;
2	const BLOCK_SIZE = 3;
3	const BLOCK_PREMIUM = 60;
4	
5	const BASE_PREMIUMS: Record<string, number> = {
6	  sword: 100,
7	  amulet: 60,
8	  staff: 80,
9	  potion: 40,
10	  rune: 25,
11	  moonstone: 25,
12	};
13	
14	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
15	
16	export function claimOffice(request: any): any {
17	  const customer = request.customer;
18	  const items = request.steps[0].items;
19	
20	  const componentCounts: Record<string, number> = {};
21	  for (const item of items) {
22	    if (COMPONENT_TYPES.has(item.type)) {
23	      componentCounts[item.type] = (componentCounts[item.type] || 0) + 1;
24	    }
25	  }
26	
27	  let totalPremium = 0;
28	  let policyBasePremium = 0;
29	  const blocksApplied = new Set<string>();
30	
31	  for (const item of items) {
32	    const isBlock = COMPONENT_TYPES.has(item.type) && componentCounts[item.type] === BLOCK_SIZE;
33	    if (isBlock && !blocksApplied.has(item.type)) {
34	      totalPremium += BLOCK_PREMIUM;
35	      policyBasePremium += BASE_PREMIUMS[item.type] * BLOCK_SIZE;
36	      blocksApplied.add(item.type);
37	    } else if (!isBlock) {
38	      let itemPremium = BASE_PREMIUMS[item.type];
39	      policyBasePremium += BASE_PREMIUMS[item.type];
40	      if (item.cursed) {
41	        itemPremium += BASE_PREMIUMS[item.type] * 0.5;
42	      }
43	      if (item.enchantment >= 5) {
44	        itemPremium += BASE_PREMIUMS[item.type] * 0.3;
45	      }
46	      totalPremium += itemPremium;
47	    }
48	  }
49	
50	  if (customer.yearsWithMHPCO >= 2) {
51	    totalPremium -= policyBasePremium * 0.2;
52	  }
53	
54	  totalPremium += policyBasePremium * 0.1;
55	
56	  return [{ premium: Math.ceil(totalPremium + PROCESSING_FEE) }];
57	}
